"""
Psalms — all four layers (echo + original + context + christ)
Updated to add comprehensive per-verse mkt-context for Psalms 18–21.
Output: data/echoes/psalms.json + mkt-original + mkt-context + mkt-christ

Psalms is quoted in the NT more than any other OT book (~80 direct citations).
Key Christological Psalms: 2 (Messianic king), 8 (Son of Man),
16 (resurrection), 22 (Passion), 45 (royal wedding), 69 (zeal/persecution),
110 (Davidic Lord), 118 (cornerstone), 119 (Torah meditation).

Psalms 18–21 context decisions:
- Ps 18: preserved almost verbatim in 2 Sam 22 — the only Davidic psalm with a second
  canonical witness; theophany (vv 7–15) draws on ANE storm-deity/divine-warrior imagery
  (Baal-Hadad, cherub war-chariot) appropriated for YHWH; v15 alludes to Reed Sea via
  gaʿar (rebuke); vv 20–24 righteousness claim = ANE covenant-treaty faithfulness
  language, not Pharisaic self-justification; v49 cited Rom 15:9 for Gentile mission
- Ps 19: two-book structure (creation vv 1–6; Torah vv 7–14); six Torah synonyms as
  comprehensive catalog; inadvertent/deliberate sin categories matching Lev 4 and Num 15
- Ps 20/21: liturgical pair — before/after battle; Ps 20 chariots-vs-name theology
  echoes the Reed Sea; Ps 21 "length of days forever" (v4) increasingly read in Second
  Temple Judaism as eschatological promise beyond natural lifespan
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_echo(book):
    p = ROOT / 'data' / 'echoes' / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_echo(book, data):
    p = ROOT / 'data' / 'echoes' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_echo(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, entries in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = entries
            else:
                seen = {(e['type'], e['target']) for e in existing[ch][v]}
                for e in entries:
                    if (e['type'], e['target']) not in seen:
                        existing[ch][v].append(e)
                        seen.add((e['type'], e['target']))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

