# INTENT: mkt-context for Psalms 1, 18–21, 22, 110 — six chapters providing the
#   historical/cultural/ANE background essential for understanding these key royal psalms;
#   Psalms 18–21 added to the bootstrap entries for Psalms 1, 22, and 110.
# CHANGE? If commentary/mkt-context/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-context/psalms.json'));
#   [print(ch, len(d[ch])) for ch in ['1','18','19','20','21','22','110']]"

PSA_CONTEXT = {
  "1": {
    "1": "<p>The Psalter (150 poems spanning roughly David\'s reign to the post-exilic period) was the hymnbook of the Second Temple — used in liturgy from the restoration (Ezra-Nehemiah) through the NT period. The Dead Sea Scrolls (1QPs, 4QPsa-r, and 11QPsa) preserve the most psalms of any biblical book among the Qumran community, indicating the Psalter\'s centrality in Jewish worship. The Psalter is organized into five books (Ps 1–41, 42–72, 73–89, 90–106, 107–150) mirroring the five books of Moses, each ending with a doxology. The arrangement suggests a canonical editorial design: the Psalter tells the story of Israel\'s covenant relationship with YHWH from Torah-delight (Ps 1) to universal praise (Ps 150).</p>"
  },
  "18": {
    "1": "<p>Psalm 18 is unique in having a second canonical witness: it appears almost verbatim in 2 Samuel 22, one of only two Davidic compositions preserved outside the Psalter. The ~18 textual variants between the two versions are philologically significant; the Psalter version is generally considered the older text. The superscription ties the psalm to the biographical moment at the close of 2 Samuel: David\'s victories over Saul and over surrounding nations (2 Sam 8). The title \"servant of the LORD\" (<em>eved yhwh</em>) is a rare, exalted designation — used of Moses (Deut 34:5; Josh 1:2), Joshua (Josh 24:29), and David (Ps 36:1); in Isaiah it becomes the title of the Suffering Servant.</p>",
    "2": "<p>The metaphor cluster — rock, fortress, deliverer, shield, horn, stronghold — maps precisely onto the Judean wilderness landscape where David hid from Saul. The Judean desert east of Jerusalem is a terrain of chalk and limestone crags, deep wadis, and naturally fortified outcrops. David specifically hid \"at the Stronghold\" in the wilderness of En-gedi (1 Sam 24:22) and at the cave of Adullam (1 Sam 22:1). These were real survival locations that became the vocabulary of faith: the geography of danger became the geography of divine protection.</p>",
    "3": "<p>The praise before the petition is significant: \"I called to the LORD, who is worthy of praise, and I am saved from my enemies.\" In the Psalter\'s thanksgiving genre, the psalmist characteristically addresses YHWH before describing the rescue — the relationship is established before the need is stated. The phrase \"worthy of praise\" (<em>mehullal</em>) situates praise as an obligation grounded in YHWH\'s character, not merely as a response to favorable circumstances.</p>",
    "4": "<p>The \"cords of death\" and \"floods of destruction\" (<em>nahaley veliyaval</em> — streams of worthlessness/chaos) employ ANE underworld mythology as the raw material of the lament. In Canaanite literature recovered from Ugarit, Mot (Death personified) swallows his enemies; the underworld has cords, ropes, and snares. Ps 18 does not endorse this mythology as cosmological fact but uses its imagery to communicate the actual mortal danger David faced: confronting Saul\'s military machinery was an encounter with the power of death.</p>",
    "5": "<p>Sheol in ancient Israelite cosmology was the realm of the dead — a dim underworld where the shades (<em>refaim</em>) existed without full life. Unlike Greek Hades, Sheol in earlier Hebrew thought was primarily characterized by absence of YHWH\'s active presence (Ps 6:5; 88:10–12) rather than active punishment. The \"snares of death\" set before the psalmist suggest Sheol as an active hunter — an image consistent with Canaanite Mot who is described as reaching out to consume. The psalmist is caught in the territory between life and the realm where YHWH\'s praise falls silent.</p>",
    "6": "<p>\"From his temple he heard my voice\" — the temple in Jerusalem had not yet been built in David\'s time; Solomon built it later (1 Kgs 6). The reference is either the heavenly temple (which the earthly sanctuary represented) or proleptic anticipation of the Jerusalem temple. The heavenly temple tradition is consistent throughout the Psalter (Ps 11:4; Hab 2:20; Isa 6:1) and in the NT (Heb 8:2; Rev 11:19). The theology of prayer in ancient Israel assumed that the earthly sanctuary was the point of connection to the divine throne-room in heaven from which YHWH heard and answered.</p>",
    "7": "<p>The theophany (vv 7–15) describes YHWH\'s descent as the divine warrior to rescue David. The Sinai theophany (Exod 19:16–18) established the pattern: earthquake, smoke, fire, and YHWH\'s descent in cloud. The mountains shaking \"at his anger\" positions YHWH\'s rescue of David as an action of cosmic significance — not merely a personal intervention but a manifestation that registers in the structure of creation. This cosmic-personal pairing (the cosmos responds to personal divine action) is characteristic of Hebrew cosmological theology: the natural and the historical are not separate domains.</p>",
    "8": "<p>\"Smoke poured from his nostrils and consuming fire from his mouth\" — the divine warrior\'s most visceral portrayal. The imagery derives from the same mythological register as the Ugaritic storm-deity Baal-Hadad, who was associated with fire, cloud, and thunder. Ps 18 appropriates this imagery for YHWH without adopting the polytheistic framework: the storm phenomena that the Canaanites attributed to Baal are here YHWH\'s own weapons of war. The \"consuming fire\" (<em>esh okelet</em>) is the same fire that appeared at Sinai (Exod 24:17; Deut 4:24: \"YHWH your God is a consuming fire\").</p>",
    "9": "<p>\"He bowed the heavens and came down\" — the descent motif in divine-warrior combat. The dramatic condescension: the highest heaven bends under YHWH\'s weight as he comes to battle. The \"dark cloud\" (<em>arafel</em>) under his feet is the dense cloud associated with YHWH\'s presence at Sinai (Exod 20:21; Deut 5:22) — the same phenomenon that led Israel through the wilderness as a pillar of cloud. YHWH descends into the storm that, from below, is the most threatening atmospheric phenomenon.</p>",
    "10": "<p>\"He mounted a cherub and flew\" — the cherub-chariot is the most distinctive image in Israelite temple theology. The ark of the covenant was flanked by two golden cherubim (Exod 25:18–22; 1 Kgs 6:23–28), and YHWH was said to be \"enthroned on the cherubim\" (1 Sam 4:4; 2 Sam 6:2; Ps 80:1). At David\'s rescue, YHWH\'s fixed throne becomes a mobile war-chariot — he rides the cherub to battle. Ezekiel\'s vision of the merkavah (Ezek 1; 10) develops this cherub-chariot theology into its most elaborate form. The image is of YHWH\'s power made mobile and directional for rescue.</p>",
    "11": "<p>\"He made darkness his shelter\" — YHWH hides himself in the storm clouds; the very thing that conceals him is his chosen dwelling. The paradox of divine hiddenness: God is most actively present in the phenomenon that obscures his presence most completely. This is the theology of the cloud at Sinai (Exod 19:16; 24:15–16) and the glory-cloud that filled the Tabernacle so completely that Moses could not enter (Exod 40:34–35). The thick, dark rain-cloud is YHWH\'s canopy, and the heavenly waters are his concealment.</p>",
    "12": "<p>\"From the brightness of his presence\" — the paradoxical radiance within the darkness. The <em>kavod</em> (glory) of YHWH was understood to be brilliantly luminous; when concealed within cloud, the cloud eventually could not contain it. The \"hailstones and coals of fire\" that burst from the cloud are simultaneously natural weather phenomena and divine weapons — the storm as YHWH\'s arsenal breaking through his own concealment to strike the enemy. The fire-within-cloud imagery recurs in Ezek 1:4 at the opening of the merkavah vision.</p>",
    "13": "<p>\"The LORD thundered from heaven\" — thunder as the divine voice is the theology of Ps 29 in miniature (\"the voice of the LORD over the waters... the voice of the LORD in power\"). The \"Most High\" (<em>Elyon</em>) is the ancient Canaanite divine title absorbed into Israelite theology — it appears in Gen 14:18–20 as Melchizedek\'s God and emphasizes YHWH\'s sovereignty over the cosmos. Here it establishes that the storm\'s thunder is the voice of the supreme divine authority, not merely one deity among others.</p>",
    "14": "<p>\"He shot his arrows and scattered them / hurled lightning bolts\" — lightning as divine arrows was a pan-ANE metaphor: Egyptian, Mesopotamian, and Canaanite traditions all associated storm lightning with divine archery. Israel\'s appropriation of this imagery for YHWH was not uncritical borrowing of mythology but the claim that the natural phenomenon everyone recognized as terrifying was specifically YHWH\'s weapon. The divine warrior\'s archery appears consistently in the Psalter (Ps 7:12–13; 45:5; 64:7) and the prophets (Hab 3:9–11).</p>",
    "15": "<p>\"The channels of the sea were exposed\" — the most explicit exodus allusion in the psalm. The Reed Sea crossing (Exod 14:21–22; 15:8) is evoked: YHWH\'s \"rebuke\" (<em>geara</em> — the powerful shout by which a deity drove back enemies or chaos-waters) split the sea and exposed the channels beneath. YHWH\'s rescue of David is framed as a personal exodus: what YHWH did for the entire nation at the sea, he does for the individual Davidic king. \"The blast of the breath of your nostrils\" echoes Exod 15:8 exactly, making the connection unmistakable.</p>",
    "16": "<p>\"He reached down from on high and took hold of me\" — the rescue imagery of the outstretched divine arm. \"From many waters\" (<em>mayim rabbim</em>) continues the sea-rescue imagery from v15: the deep waters associated with chaos and death (Gen 7:11; Ps 69:1–2; 93:3–4) are the domain from which YHWH extracts the psalmist. The \"many waters\" carried mythological connotations in ANE cosmology as the primordial chaos that opposed divine order; YHWH\'s control over them demonstrated his sovereignty over the cosmos.</p>",
    "17": "<p>\"Rescued me from my powerful enemy\" — the social and political reality behind the cosmic imagery. The \"powerful enemy\" and \"those who hated me — stronger than I\" refers concretely to Saul\'s military forces, which David as a fugitive could not match. The cosmic language of divine rescue (drawing from deep waters, defeating chaos) describes the actual political-military situation: David was vastly outgunned, and his survival was inexplicable by military arithmetic alone. The cosmic framing is not exaggeration but theological interpretation of a genuine crisis.</p>",
    "18": "<p>\"The day of my disaster\" — <em>ed</em> (calamity, day of doom) is a term used in Deut 32:35, Job 21:30, and Jer 46:21 for the decisive crisis-moment. The \"day\" of calamity was understood as the moment when one\'s enemies had the advantage and the outcome hung in the balance. The declaration that \"the LORD was my support\" (<em>misad</em>) in that specific moment is a theological claim: YHWH was actively present and sustaining at the worst point, not merely available in the aftermath.</p>",
    "19": "<p>\"He brought me out into an open place\" — the spatial metaphor of rescue: from the narrow place of danger to the spacious place of safety. This contrast (narrow/open; constricted/free) is fundamental to the ANE experience of distress and rescue. The root word <em>merkhav</em> (broad/open place) is the opposite of <em>metzar</em> (the narrow strait, distress). In Hebrew idiom, trouble was being in a narrow place; salvation was being brought into open space. The psalmist\'s rescue is experienced as a spatial liberation that corresponds to the emotional and physical reality of escape.</p>",
    "20": "<p>The righteousness claim that opens vv 20–24 must be understood within ANE covenant-treaty categories. In Hittite and Assyrian suzerainty treaties, the vassal who faithfully kept the treaty terms was entitled to invoke the great king\'s protection. David\'s claim of righteousness and clean hands is covenant-loyalty language: he kept his side of the covenant with YHWH, and YHWH is now honoring his treaty obligation to defend the faithful vassal. This is not a claim of absolute moral perfection but of covenant faithfulness — the language of a loyal subordinate invoking treaty protections.</p>",
    "21": "<p>\"I have kept to the LORD\'s ways and have not turned away from my God in rebellion\" — the language of covenant loyalty rather than sinlessness. The \"ways of the LORD\" (<em>darkhe Yhwh</em>) are the covenant terms and divine statutes. Not \"turning away in rebellion\" — the specific language of deliberate covenant violation. David\'s claim is that he has not deliberately repudiated his covenant relationship with YHWH, even under the pressure of Saul\'s persecution. The contrast with Saul (who did precisely this, 1 Sam 13:13–14; 15:22–23) is implied and would have been clear to the original audience.</p>",
    "22": "<p>\"All his rules were set before me\" — the Torah as the covenant document that the Davidic king was required to study and keep (Deut 17:18–20: the king must write a copy of the Torah and read it all his days). The explicit requirement that the king study Torah distinguished Israelite kingship from ANE models where the king was above law; in Israel, the king was specifically subordinated to the covenant document. David\'s placing of YHWH\'s rules \"before me\" is a reference to this royal Torah-practice that defined legitimate Davidic kingship.</p>",
    "23": "<p>\"I was blameless before him\" — <em>tamim</em> (blameless, complete, without defect) is the term used for animals acceptable for sacrifice (Lev 1:3, 10), for Noah (Gen 6:9: \"blameless in his generation\"), and for Job (Job 1:1). It does not mean sinless but designates wholeness and integrity within the covenant relationship. Similarly \"kept myself from wrongdoing\" is the language of guarding against covenant violation, not claiming freedom from any moral failing. The categories are forensic and relational, not absolute moral perfection.</p>",
    "24": "<p>The restatement of vv 20–23 in v24 creates a liturgical inclusion — the covenant-faithfulness claim is framed and reinforced. In the context of the Davidic theology, this repetition carries structural weight: YHWH\'s \"reward\" (<em>gamal</em> — the reciprocal dealing that results from a relationship) is the covenant response to David\'s covenant faithfulness. The theological principle (loyalty receives loyalty) will be stated explicitly in vv 25–26, where the mirror-principle of the covenant is articulated.</p>",
    "25": "<p>\"To the faithful you show yourself faithful; to the blameless you show yourself blameless\" — the covenant-mirror principle: YHWH reflects back to his people the quality they bring to the relationship. Those who bring <em>hesed</em> (covenant loyalty) receive <em>hesed</em>; those who bring integrity encounter YHWH\'s own integrity. The principle appears in NT form in Matt 5:7 (\"blessed are the merciful, for they shall receive mercy\") and Matt 7:2 (\"the measure you use will be measured back to you\"). This is the organic logic of a personal relationship, not mechanical tit-for-tat.</p>",
    "26": "<p>\"To the devious you show yourself cunning\" — not that YHWH becomes deceptive, but that those who approach YHWH with a crooked covenant-relationship encounter the consequences of their own deviousness within YHWH\'s moral order. The devious who expected to manipulate YHWH find instead that their schemes are subverted. This principle of divine moral mirroring is why the enemies in vv 37–42 are destroyed by their own trap — YHWH works through the consequences of wickedness itself rather than introducing an external punishment.</p>",
    "27": "<p>\"You save an afflicted people\" — the <em>am ani</em> (poor/afflicted people) are the consistently identified recipients of divine rescue in the Psalter: those without social power or human protectors. \"But proud eyes you humble\" — the reversal of social status is a consistent pattern in YHWH\'s economy (1 Sam 2:7–8; Ps 75:7; Prov 3:34; James 4:6; Luke 1:51–53). The rescue of David — a fugitive shepherd against the anointed king — is itself a demonstration of this principle: YHWH took the side of the marginalized against the powerful.</p>",
    "28": "<p>\"You light my lamp\" — the lamp (<em>ner</em>) as a symbol of life, continuation, and dynastic hope. In 2 Sam 21:17, David is called \"the lamp of Israel\" — to extinguish David would be to extinguish the covenant-dynasty. The \"lamp for David\" became a covenant-formula: 1 Kgs 11:36 (YHWH will give David\'s son \"a lamp\" in Jerusalem); 15:4; 2 Kgs 8:19; Ps 132:17 (\"I have prepared a lamp for my anointed\"). The lighting of the lamp is simultaneously a metaphor for personal survival and dynastic continuation through the Davidic covenant.</p>",
    "29": "<p>\"By your help I can charge against a raiding party / by my God I can scale a wall\" — specific military operations common in David\'s career: the <em>gedud</em> (raiding band) against which David counter-raided while at Ziklag (1 Sam 30:1–20), and scaling city walls in siege warfare (2 Sam 11:20–21; 20:15). Both were standard ancient warfare techniques. The verse claims divine enablement for offensive military action — patron-deity theology: the deity arms and empowers the warrior-king for operations that ordinary human strength cannot accomplish.</p>",
    "30": "<p>\"This God — his way is perfect / his word is refined and true\" — YHWH\'s reliability expressed through two quality-control metaphors. <em>Tamim</em> (perfect, complete, without defect) applied to YHWH\'s way, and <em>tzerufa</em> (refined/smelted — the word for metal refined in fire) applied to his word. The refining image appears also in Ps 119:140 and Prov 30:5 (\"every word of God is flawless\"). The absolute trustworthiness of YHWH is the ground of military confidence: one goes to battle knowing the covenant-Lord\'s word does not fail.</p>",
    "31": "<p>\"Who is God besides the LORD? And who is a rock except our God?\" — the rhetorical questions assert YHWH\'s incomparability without necessarily denying the existence of other spiritual powers. This represents the trajectory from monolatry (worshipping one God while acknowledging others exist) toward monotheism (denying others\' existence). In ANE culture where each nation had its own patron deity, these questions assert a qualitative difference: YHWH is incomparable in the functions that matter — rescue, reliability, military power. No other deity gives this quality of covenant protection.</p>",
    "32": "<p>\"It is God who arms me with strength\" — the divine arming of the warrior. In ANE royal ideology, the king was the deity\'s warrior, equipped with divine power before battle. Egyptian pharaohs were described as armed and accompanied by the sun-god Ra; Mesopotamian kings received their weapons from the gods. Israel\'s Davidic ideology participates in this royal-warrior pattern but within strict monotheism: only YHWH arms and empowers; no subsidiary deity is involved. \"Makes my way perfect\" — the same <em>tamim</em> applied to the king\'s path of action as to YHWH\'s way in v30.</p>",
    "33": "<p>\"He makes my feet like the feet of a deer\" — the deer as a model of sure-footed speed in rocky terrain. The Judean hill country where David fought is rugged — the limestone ridges and rocky wadis require agility. Deer (<em>ayalot</em>) were proverbially sure-footed on difficult terrain. Hab 3:19 uses the same image: \"He makes my feet like the feet of a deer and enables me to go on the heights.\" The divine gift of agile footing is a practical military advantage in the specific geography of Judean guerrilla warfare, not merely a spiritual metaphor.</p>",
    "34": "<p>\"He trains my hands for battle / my arms can bend a bow of bronze\" — the bow of bronze was a prestige weapon; most bows were wood and sinew, but bronze-reinforced bows were exceptional equipment. \"Trains my hands\" (<em>melammeyd yaday</em>) — the verb for teaching a skill; YHWH is presented as the warrior-trainer who imparts martial skill. This military apprenticeship theology appears in ANE traditions where warriors received skill from their patron deity; Israel\'s version makes YHWH specifically the one who teaches warfare to the Davidic king.</p>",
    "35": "<p>\"The shield of your salvation / your right hand held me up / your gentleness made me great\" — three divine gifts that made David\'s greatness possible. \"Your gentleness\" (<em>vanatekha</em> — or possibly \"your condescension\") is the surprising word: divine greatness expressed not through overwhelming force alone but through the humble attention YHWH gave to David\'s weakness. The LXX reads this as <em>paideia</em> (education/discipline) — YHWH\'s formation of David through difficulty. David\'s military success flowed from a relationship of gracious divine condescension toward a dependent vassal.</p>",
    "36": "<p>\"You gave wide room for my steps beneath me, and my feet did not slip\" — the return to the spatial metaphor of v19 (<em>merkhav</em>, wide/open place). The divinely secured footing echoes v33: sure-footed on the heights, now stable on the widened path. The stability of footing was a literal concern for ancient warriors fighting on rocky terrain and in siege operations. Slipping meant death; YHWH\'s gift of sure footing is both the practical military benefit and the metaphor for moral stability within the covenant relationship.</p>",
    "37": "<p>Verses 37–45 describe the military victory that followed divine empowerment. The language is conventional ANE victory-inscription language: the king pursues, overtakes, and destroys until none remain. Assyrian annals described enemies \"ground to dust,\" \"trampled underfoot,\" \"scattered like chaff.\" Egyptian victory steles used similar formulas. Ps 18 employs this shared ANE military rhetoric, showing that Hebrew victory poetry participated in a common ancient Near Eastern literary tradition — the specific content (YHWH as the source of power) is distinctively Israelite within a shared formal vocabulary.</p>",
    "38": "<p>\"I struck them down so that they could not rise / they fell under my feet\" — the complete subjugation formula. In the ANE, complete military victory was symbolized by the victor placing his foot on the necks of the defeated (Josh 10:24 — Joshua commanded his commanders to do this to the five Amorite kings). The image appears in Egyptian royal art: Pharaoh with his foot on the necks of enemies. Ps 18\'s imagery participates in this royal-victory iconography as the standard language of total conquest.</p>",
    "39": "<p>\"You armed me with strength for the battle\" — the resumptive statement connecting the divine arming (v32) with the battle outcome (vv 37–40). The theological structure is deliberate: the victory is bracketed by statements of divine origin. The military narrative in the middle is not autonomous human achievement but the outworking of divine empowerment. This prevents the psalmist from attributing the victory to his own skill or strength — the credit flows back to YHWH who armed, trained, and sustained him throughout.</p>",
    "40": "<p>\"You made my enemies turn their backs in retreat\" — the \"backs\" (<em>oref</em>) of fleeing enemies was a standard image of complete rout. In ancient combat, turning your back to the enemy meant completely abandoning defensive formation — a soldier whose back was turned could be struck from behind. Egyptian military texts describe \"making the enemies turn their backs\" as the decisive moment of victory. YHWH causes this rout as his contribution to the battle, not the result of David\'s superior tactics.</p>",
    "41": "<p>\"They cried for help, but there was no one to save them — they even cried to the LORD, but he did not answer them\" — this verse is remarkable for claiming that David\'s enemies called on YHWH without success. In ancient warfare, enemies often called on the victor\'s god when their own gods failed. The claim here is that YHWH did not answer because these enemies had no covenant relationship with him. The theological point: YHWH answers the covenant-faithful, not those who invoke him as a last resort without prior relationship or covenant standing.</p>",
    "42": "<p>\"I ground them fine as windblown dust / threw them out like mud from the streets\" — the two images of the utterly defeated: dust before the wind (the lightest, most dispersible substance) and street mud (the most contemptible, walked-upon substance). Both appear in ANE destruction poetry: Assyrian annals describe defeated enemies scattered \"like dust before the wind.\" The imagery communicates not merely military defeat but social humiliation — the proud enemies are reduced to the least significant possible state, with no honor remaining.</p>",
    "43": "<p>\"You saved me from conflicts with my own people / you made me head of the nations\" — the internal and external dimensions of Davidic rule. The \"conflicts with my own people\" refers to tribal tensions within Israel, specifically Saul\'s tribal base (Benjamin) and later Absalom\'s revolt. \"Head of the nations\" reflects the historical scope of David\'s empire: 2 Sam 8 records his conquests of Moab, Ammon, Edom, Philistia, and Aram. This unprecedented territorial reach made David the suzerain of client-nations for the first and only time in Israel\'s monarchic history.</p>",
    "44": "<p>\"As soon as they heard of me, they obeyed / foreigners submitted to me\" — the word-of-reputation as a military instrument. In ANE politics, a king\'s name/reputation preceded his armies; the fear generated by report of his victories caused capitulation before battle. The Rahab narrative (Josh 2:9–11) depicts this: the Jerichoites had heard of YHWH\'s acts and their hearts melted before Israel arrived. David\'s international reputation accomplishes the same pacification function without requiring direct combat in every case.</p>",
    "45": "<p>\"Foreigners lost their courage and came out of their fortresses trembling\" — the psychological collapse of fortified defenders. ANE sieges regularly achieved capitulation without assault when defenders recognized the hopelessness of resistance. The emotional vocabulary — lost courage (wither/fade away), trembling — describes the complete psychological breakdown of a population that had counted on their fortifications and found them insufficient against YHWH\'s anointed. The fortress was the ancient world\'s ultimate security; its inadequacy before David was a theological statement.</p>",
    "46": "<p>\"The LORD lives!\" — <em>hay-Yhwh</em> (YHWH is alive) is both an oath formula (1 Sam 14:39; 26:10; 2 Sam 4:9) and a theological declaration that distinguishes YHWH from the dying and rising deities of Canaanite mythology. In the Baal cycle texts from Ugarit, Baal dies and must be resurrected each year — the agricultural fertility of the land depended on Baal\'s annual resurrection. YHWH is permanently, continuously alive; the resurrection mythology does not apply to him. The acclamation \"Blessed be my Rock\" echoes Deut 32:4 and the Song of the Sea (Exod 15:2).</p>",
    "47": "<p>\"The God who gives me justice\" — the nĕqamah (vengeance/justice) YHWH exercises on behalf of the covenant-keeper is not private revenge but the judicial action of the divine suzerain defending his vassal. Deut 32:35 declares \"vengeance is mine and recompense\" — YHWH claims the right of judicial retribution, which means the covenant-keeper can appeal to him rather than taking matters into their own hands. David consistently refused to take personal vengeance on Saul precisely because this principle was clear to him (1 Sam 24:12–15).</p>",
    "48": "<p>\"You rescued me from my enemies / you lifted me above those who rose against me\" — the social-vertical dimension of the rescue. Being \"lifted above\" one\'s enemies was both military (holding the high ground) and social (being publicly vindicated above those who claimed superiority). Honor-shame culture required public vindication as well as private rescue: it was not enough to survive; one needed to be seen as elevated above the adversary. YHWH\'s rescue includes this social dimension of public vindication before the community that witnessed the conflict.</p>",
    "49": "<p>\"Therefore I will give you thanks, O LORD, among the nations, and sing praises to your name\" — Paul cites this verse in Romans 15:9 as one of four OT texts demonstrating that the Gentile mission was always YHWH\'s plan (\"so that the Gentiles might glorify God for his mercy... \'Therefore I will praise you among the Gentiles\'\"). The Davidic king\'s testimony to YHWH\'s greatness among the nations becomes, in Paul\'s reading, the pattern that Christ fulfills: the ultimate Davidic representative praising the Father among all peoples and gathering them into covenant worship.</p>",
    "50": "<p>\"Steadfast love to his anointed — to David and his descendants forever\" — the <em>hesed</em> (covenant loyalty) extended to <em>mashiakh</em> (his anointed) is the Davidic covenant of 2 Sam 7 in summary form. The promise of eternal (<em>olam</em>) covenant loyalty necessarily points beyond any particular king\'s lifespan. The word <em>mashiakh</em> (anointed one) introduces the Messianic register that becomes central in the NT — the Christ is the ultimate Davidic anointed to whom this everlasting covenant loyalty is addressed. This verse closes Psalm 18 as both a historical declaration and an eschatological promise.</p>"
  },
  "19": {
    "1": "<p>Psalm 19 has a famous bipartite structure: vv 1–6 (creation/cosmic revelation) and vv 7–14 (Torah/revealed revelation). C.S. Lewis called this \"the greatest poem in the Psalter and one of the greatest lyrics in the world.\" The \"two-book\" framework — God\'s revelation through creation and through Scripture — became foundational in both Jewish and Christian theology of revelation. Every major ANE culture affirmed that the cosmos revealed divine character (Egyptian Akhenaten\'s Hymn to the Sun; Mesopotamian cosmic hymns). Ps 19\'s distinctiveness is the Torah section, which claims that special revelation surpasses and interprets the cosmic witness.</p>",
    "2": "<p>\"Day after day pours out speech / night after night reveals knowledge\" — the perpetual, accumulating cosmic testimony. Each day and night adds to the running testimony of creation without repeating it. The verb <em>navah</em> (pours out, gushes forth) is the verb for a spring of water welling up — the testimony is not sparse or sporadic but overflowing. The sequence of days and nights functions like witnesses in a legal proceeding: they testify without ceasing, each one adding to the cumulative case for the Creator\'s reality and character.</p>",
    "3": "<p>\"There is no speech, there are no words — their voice cannot be heard\" — the paradox that the creation speaks (v2) yet does so without human language. This distinguishes cosmic revelation from verbal revelation: the heavens communicate meaning without propositional speech. Paul\'s use of this psalm in Rom 1:19–20 interprets the cosmic testimony as sufficient to make humans \"without excuse\" — the testimony is real and morally consequential even without linguistic form. The distinction between non-verbal and verbal revelation became fundamental in Christian theological epistemology.</p>",
    "4": "<p>\"Yet their proclamation goes out through all the earth\" — the universal scope of cosmic revelation. Paul (Rom 10:18) quotes this verse, applying it to the gospel: as the heavenly proclamation has gone to all the earth, so also the gospel. \"In the heavens he has pitched a tent for the sun\" — <em>ohel</em> (tent) domesticates the sun from a self-sufficient deity to a creature with a YHWH-given dwelling. Egyptian sun-worship centered on Ra\'s self-generated power; Ps 19 presents the sun as inhabiting a tent that YHWH pitched for it — a subtle but thorough polemic against solar worship.</p>",
    "5": "<p>\"Which rises like a bridegroom leaving his chamber / rejoices like a champion\" — two personifications of the sun: the bridegroom emerging from the bridal chamber (<em>huppah</em> — the wedding canopy) full of joyful energy, and the warrior-athlete (<em>gibbor</em>, champion/mighty man) eager to run the course. In Canaanite religion, the sun-deity Shamash was associated with both justice and vitality. Ps 19 appropriates the mythological sun-god\'s vigor but transfers it to a creature: the sun\'s energy is YHWH\'s gift, not the sun\'s own divine nature.</p>",
    "6": "<p>\"Nothing is hidden from its heat\" — the sun\'s penetrating reach as a theological image. Everything is exposed to the sun\'s light and heat; nothing escapes. This verse functions as the bridge between the creation section and the Torah section: the sun that illuminates and exposes all things in creation is the natural counterpart to the Torah that reveals everything about human moral life (v12\'s \"hidden faults\"; v13\'s \"willful sins\"). The all-seeing sun prepares theologically for the all-revealing Torah that follows in vv 7–14.</p>",
    "7": "<p>The Torah-section (vv 7–14) uses six synonyms for divine revelation — a completeness that Second Temple Judaism recognized as signaling the total scope of YHWH\'s communication: (1) <em>torah</em> (instruction/teaching), (2) <em>edut</em> (testimony/decree), (3) <em>piqudim</em> (precepts/orders), (4) <em>mitzvah</em> (commandment), (5) <em>yirat Yhwh</em> (fear of the LORD), (6) <em>mishpatim</em> (judgments/ordinances). Each is paired with an attribute and an effect. Torah-piety in ancient Israel was not about legal compliance but the transformative encounter with YHWH\'s revealed character, which alone could revive the soul and make the simple wise.</p>",
    "8": "<p>\"The precepts of the LORD are right, bringing joy to the heart\" — the Torah as the source of emotional flourishing rather than burden. Second Temple Jewish teachers carefully distinguished the joy (<em>simhah</em>) of Torah-observance from mechanical legal compliance; the Talmud preserves traditions of scholars who wept with joy over Torah insights. This positive Torah-piety is characteristic of the Psalter (Ps 1:2; 112:1; 119:14, 16, 24, 35, 47, 92, 111, 162, 174). The joy comes not from rule-keeping as achievement but from the alignment of life with YHWH\'s revealed will.</p>",
    "9": "<p>\"The fear of the LORD is pure, enduring forever\" — the sixth synonym peaks with <em>yirat Yhwh</em> (fear of the LORD) as one of the synonyms for Torah itself. \"Fear of the LORD\" was understood in Second Temple Judaism as the comprehensive term for the right orientation toward YHWH from which all specific covenant-keeping flowed (Prov 1:7; 9:10; Eccl 12:13: \"the conclusion of the matter — fear God and keep his commandments\"). Its pairing with \"endures forever\" distinguishes it from temporary cultic observance: the covenantal orientation toward YHWH outlasts the ritual system that serves it.</p>",
    "10": "<p>\"More desirable than gold / sweeter than honey, than honey dripping from the comb\" — Torah as aesthetic and material excellence. The physical pleasure of taste as a metaphor for intellectual and spiritual pleasure: the Talmud records that children beginning Torah study were given honey to taste with the letters, so that Torah would be associated with sweetness from the first encounter. The same metaphor appears in Ps 119:103; Rev 10:9–10 (where the opened scroll tastes sweet as honey). The comparison to gold establishes Torah\'s material worth above the highest human treasure.</p>",
    "11": "<p>\"Moreover, your servant is warned by them\" — the Torah\'s protective function: it warns against dangers that the psalmist would not perceive through natural awareness alone. \"In keeping them there is great reward\" — the reward is both intrinsic (life oriented by YHWH\'s instruction simply goes better, Deut 28:1–14) and covenantal (keeping covenant terms activates covenant blessings). The practical wisdom tradition and the formal covenant theology overlap here: Torah is simultaneously wise counsel for human flourishing and the treaty-terms of the divine-human relationship.</p>",
    "12": "<p>\"Who can understand his own errors? Cleanse me from sins I cannot see\" — the category of hidden/inadvertent sins was a recognized legal and liturgical category in ancient Israel. Lev 4 and Num 15:22–29 specified that inadvertent violations of the Torah (<em>shegagah</em>, unintentional sin) could be atoned through specific sin-offerings. The liturgical system acknowledged that humans regularly transgress YHWH\'s standards without awareness. The regular daily sacrificial system at the Tabernacle/Temple partially addressed this category: the ongoing sacrificial maintenance was partly for the cumulative weight of unrecognized transgressions.</p>",
    "13": "<p>\"Keep your servant from willful sins / let them not have mastery over me\" — deliberate, high-handed acts contrasted explicitly with v12\'s inadvertent sins. Num 15:30–31 is clear: deliberate sin \"with a high hand\" was cut off from the Mosaic atonement system; no sin-offering covered it. \"Blameless and clean of great rebellion\" — the category of deliberate covenant violation that only YHWH\'s direct mercy could address. This is why David\'s prayer for forgiveness of deliberate sin in Ps 51 (after his adultery and murder) represents a theological breakthrough beyond the formal sacrificial system.</p>",
    "14": "<p>\"May the words of my mouth and the meditation of my heart be pleasing in your sight\" — the application of the sacrificial vocabulary to speech and thought. \"Pleasing\" (<em>leratzon</em>) is the technical term for acceptable sacrifice (Lev 1:3; Isa 56:7: \"their burnt offerings and sacrifices will be accepted on my altar\"). The psalmist presents his entire inner and outer life as a sacrifice offered to YHWH. \"My rock and my redeemer\" — <em>goali</em> (my kinsman-redeemer) introduces the family-protection theology: YHWH as the nearest relative who takes responsibility for the endangered family member (Ruth 2:20; Isa 43:14; 44:6).</p>"
  },
  "20": {
    "1": "<p>Psalm 20 and Psalm 21 form a liturgical pair for royal military contexts: Ps 20 is the community\'s prayer for the king before battle; Ps 21 is the community\'s thanksgiving after the king returns victorious. This before/after structure likely reflects an actual liturgical ceremony at the temple before the king\'s military departure. ANE parallels are numerous: Egyptian and Mesopotamian armies conducted ritual prayer, sacrifice, and divination before campaigns; Babylonian priests consulted omens. Israel\'s equivalent was inquiry of YHWH through the ephod or a prophet (1 Sam 23:2; 30:8; 2 Sam 5:19). The name \"Jacob\" invokes the patriarch and the covenant community.</p>",
    "2": "<p>\"May he send you help from his sanctuary and support you from Zion!\" — the temple as the military command center of YHWH. The ark of the covenant had been carried into battle as YHWH\'s mobile throne (Num 10:35: \"Arise, O LORD, and let your enemies be scattered\"; 1 Sam 4:3–11 — where taking the ark into battle without YHWH\'s guidance proved disastrous). After Solomon built the temple on Zion, Jerusalem became the permanent location from which YHWH\'s military support was dispatched. The petition reflects genuine belief in YHWH\'s active military engagement on Israel\'s behalf from his Zion dwelling.</p>",
    "3": "<p>\"May he remember all your offerings and accept your burnt sacrifices\" — the sacrificial system before military campaign. The king was expected to offer sacrifices before departure; the divine acceptance of those offerings (signaled by fire from heaven or a prophetic oracle — 2 Chr 7:1; Lev 9:24) was understood as divine endorsement of the campaign. Saul\'s failure to wait for Samuel before offering sacrifice at Gilgal (1 Sam 13:8–14) was not an administrative error but a theological catastrophe; acting without proper sacrifice meant acting without YHWH\'s endorsement, which cost him the kingdom.</p>",
    "4": "<p>\"May he grant you your heart\'s desire and fulfill all your plans\" — the king\'s military plans are presented as worthy of divine fulfillment because the Davidic king\'s purposes are aligned with YHWH\'s purposes. ANE royal ideology consistently presented the king\'s plans as divinely inspired and his campaigns as divinely mandated. In Israel, this alignment required the king to remain within the covenant framework — a king who acted outside covenant terms could not expect YHWH to fulfill his plans, as Ahab discovered when his battle plan was divinely undone (1 Kgs 22).</p>",
    "5": "<p>\"May we shout for joy at your victory and raise our banners in the name of our God\" — the communal celebration of the king\'s military success as the community\'s own victory. The battle was not the king\'s private war but Israel\'s covenant war; the victory belonged to the whole community. \"Banners\" (<em>degalim</em>) in the name of God: ANE armies fought under divine standards bearing the symbols of their patron deities. At Rephidim, Moses built an altar called \"YHWH-Nissi\" (YHWH is my Banner, Exod 17:15) after the victory over Amalek; the divine name was Israel\'s military standard.</p>",
    "6": "<p>\"Now I know that the LORD saves his anointed one\" — the shift from congregational prayer (vv 1–5) to individual confident assertion may reflect a priestly or prophetic oracle delivered in the temple liturgy. Before a military campaign, the king or a designated prophet would receive a divine word of assurance; the oracle would then be proclaimed to the assembled community. This pattern appears in 2 Chr 20:14–17 (the Levite Jahaziel rises with a prophetic oracle at Jehoshaphat\'s battle liturgy) and 2 Chr 32:7–8 (Hezekiah\'s encouragement before Sennacherib\'s siege).</p>",
    "7": "<p>\"Some boast in chariots and some in horses, but we will boast in the name of the LORD our God\" — the central contrast of Israelite covenantal faith. The horse-and-chariot combination was the decisive military technology of the ANE from c.1650 BC onward; Egypt\'s military power was its chariot forces. The Reed Sea narrative was the defining theological event: YHWH destroyed \"horse and rider\" (Exod 15:1) as the supreme demonstration that military hardware cannot overcome divine power. Deut 17:16 explicitly prohibited the king from multiplying horses; Solomon violated this (1 Kgs 10:26–29), and the prophets treated it as spiritual compromise.</p>",
    "8": "<p>\"They collapse and fall, but we rise and stand firm\" — the military-reversal pattern that structures much of Israel\'s historical theology. The pattern of the militarily superior collapsing and the covenant-faithful standing recurs: Sennacherib\'s army of 185,000 destroyed outside Jerusalem in a single night (2 Kgs 19:35–36); Gideon\'s 300 defeating Midian (Judg 7); David against Goliath (1 Sam 17). These historical events were interpreted as confirmation of the theology expressed here: human military calculation is defeated by YHWH\'s intervention on behalf of his covenant people.</p>",
    "9": "<p>\"LORD, give victory to the king! Answer us when we call\" — the concluding petition in which \"the king\" may be simultaneously the Davidic monarch and YHWH himself as the ultimate king. The ambiguity is theologically productive: in praying for the Davidic king\'s victory, Israel prays for YHWH\'s own kingship to be expressed through his anointed. The NT reading of these royal psalms as Christological draws on precisely this ambiguity: the prayer for the Davidic king is ultimately a prayer for the one King whose victory is definitive and eternal.</p>"
  },
  "21": {
    "1": "<p>Psalm 21 is the post-battle thanksgiving that completes the liturgical pair with Psalm 20. Where Psalm 20 prayed for victory, Psalm 21 celebrates it. The structural echo is deliberate: Ps 20:13 asks YHWH to \"rise in your strength,\" and Ps 21:1 begins \"the king rejoices in your strength\" — the petition has been answered. The psalm likely functioned in a temple ceremony marking the king\'s return from a successful campaign. The \"strength\" celebrated is divine strength expressed through the Davidic king, not the king\'s autonomous military capacity — the derivative nature of royal power is consistently maintained.</p>",
    "2": "<p>\"You have given him his heart\'s desire\" — the explicit fulfillment of Ps 20:4\'s petition (\"may he grant you your heart\'s desire\"). The liturgical design is clear: the congregation prayed (Ps 20), and the thanksgiving declares the answer (Ps 21). This prayer-fulfillment-thanksgiving structure is the standard form of Hebrew petition psalms and reflects actual liturgical practice: petitions were formally remembered and answered petitions formally acknowledged in temple worship. The social function of this liturgy was the regular renewal of communal confidence in YHWH\'s responsiveness to covenant prayer.</p>",
    "3": "<p>\"You set a crown of finest gold upon his head\" — <em>ateret paz</em> (wreath of pure/refined gold). Military victory was regularly celebrated with coronation-renewal ceremonies in the ANE: the victory confirmed and renewed the king\'s divine mandate. Egyptian pharaohs were re-crowned after significant victories; Mesopotamian kings offered crowns to their patron deities at victory celebrations. The Davidic theology appropriates this royal pattern: YHWH crowns his king with the finest gold as acknowledgment of the covenant-victory that was YHWH\'s own gift. The word <em>paz</em> (refined gold) appears in Ps 19:10 for Torah\'s surpassing value.</p>",
    "4": "<p>\"He asked you for life, and you gave it to him — length of days forever and ever\" — <em>hayyim</em> (life) petitioned and granted with <em>olam vaed</em> (forever and ever). In the immediate historical context this was the standard royal prayer for a long reign and enduring dynasty; the ANE equivalent was \"may the king live forever\" (1 Kgs 1:31; Dan 2:4). But in Second Temple Jewish interpretation, \"length of days forever\" was increasingly read as pointing beyond natural lifespan — to a life that transcended death. The NT reads this as fulfilled in Christ\'s resurrection: the Davidic Son receives life that is genuinely eternal.</p>",
    "5": "<p>\"Through your salvation his glory is great / you have bestowed splendor and majesty upon him\" — the king\'s splendor and honor are derivative, not innate. ANE royal ideology often presented the king as semi-divine or as the earthly manifestation of the deity\'s own glory; Egyptian pharaohs were sons of Ra who shared in divine nature. Israelite royal theology consistently distinguishes: the king\'s glory comes through YHWH\'s salvation — it is a bestowed dignity, not an inherent one. The king is great because YHWH made him great through a specific historical intervention on his behalf.</p>",
    "6": "<p>\"For you make him most blessed forever / you fill him with gladness in your presence\" — blessings and gladness in the divine presence. \"In your presence\" (<em>beAnekha</em> — literally \"in your face\") is the fullest possible expression of covenant closeness: to be in YHWH\'s face without being consumed (Exod 33:20). The king\'s gladness in YHWH\'s presence echoes the gladness of those who survive battle to see the king\'s face again — and both point toward the eschatological joy of Ps 16:11: \"in your presence there is fullness of joy; at your right hand are pleasures forevermore.\"</p>",
    "7": "<p>\"For the king trusts in the LORD / through the steadfast love of the Most High he will not be shaken\" — the theological foundation of royal security: trust in YHWH\'s <em>hesed</em> (covenant loyalty) rather than military power. <em>Elyon</em> (Most High) — the ancient divine title that appears in Gen 14:18–20 (Melchizedek\'s God who blessed Abraham) and Deut 32:8 (where Elyon assigned the nations their territories). By invoking Elyon, the psalm situates the Davidic king\'s security within YHWH\'s cosmic governance of all nations, not merely his covenant with Israel specifically.</p>",
    "8": "<p>\"Your hand will reach all your enemies / your right hand will seize those who hate you\" — the second half of Psalm 21 (vv 8–12) shifts subject: now YHWH directly acts against the king\'s enemies, not merely through the king. The divine right hand (<em>yeminekha</em>) is consistently the hand of power, rescue, and judgment (Exod 15:6; Ps 118:15–16). The shift from the king\'s action (vv 1–7) to YHWH\'s direct action (vv 8–12) is significant: the ultimate defeat of enemies is YHWH\'s own work, not achievable through human military capacity.</p>",
    "9": "<p>\"You will make them like a burning oven in the time of your anger\" — the burning oven (<em>tannur</em>) image appears in prophetic judgment texts: Mal 4:1 (\"for behold, the day is coming, burning like an oven, and all the arrogant and all evildoers will be stubble\"). \"The time of your anger\" — the day of YHWH\'s wrath, which in prophetic literature develops into the eschatological \"Day of the LORD.\" The military defeat of the king\'s enemies is presented within an eschatological framework: YHWH\'s anger against covenant-enemies points toward and prefigures final judgment.</p>",
    "10": "<p>\"You will destroy their offspring from the earth / their descendants from among mankind\" — the covenant curse of no posterity, which was among the most dreaded punishments in ANE culture. In the Esarhaddon Vassal Treaties (c.672 BC), covenant-violation curses included: \"may your offspring not inherit your land; may your name and your seed be cut off.\" The destruction of the opponent\'s line meant no future monument, no memorial, no continuation — complete annihilation from history. The Deut 28:18, 41 covenant curses include childlessness and loss of children as covenant punishments for Israel\'s own violations.</p>",
    "11": "<p>\"For they intended evil against you and devised a plot they cannot carry out\" — the conspiracy that fails echoes Ps 2:1–3 (the nations plotting against YHWH and his anointed) and Ps 33:10–11 (YHWH frustrates the plans of the nations but his own purposes stand). The motif of the plot that cannot be executed against YHWH and his anointed is fundamental to Israel\'s theodicy: hostile powers are not YHWH\'s equals; their schemes are inherently limited by their opposition to the one who controls the cosmos and history.</p>",
    "12": "<p>\"You will put them to flight as you aim your bow at their faces\" — the divine archer who drives enemies into flight by the mere aiming of his bow. The bow-and-arrow as divine weapon appeared in the theophany of Ps 18:14; here YHWH\'s archery achieves rout without needing to shoot — the threat alone is sufficient. In ANE royal iconography, the king as divine archer (drawing the bow against enemies) is ubiquitous in Egyptian and Assyrian art; Israel transfers this imagery to YHWH directly, without the human royal intermediary.</p>",
    "13": "<p>\"Rise in your strength, O LORD! We will sing and praise your mighty deeds\" — the closing doxology returns to the pre-battle language of Ps 20:13 (\"rise in your strength, O LORD!\") but now as praise rather than petition. The congregation that prayed before battle now praises after; the \"mighty deeds\" (<em>gevurot</em>) celebrated are YHWH\'s own acts expressed through the Davidic victory. The royal psalms consistently return to this pattern: the king\'s military success is ultimately YHWH\'s power displayed through the covenant instrument, and the final praise is directed to YHWH alone.</p>"
  },
  "22": {
    "1": "<p>Psalm 22 is the most cited OT Psalm in the NT Passion narratives. Its historical background (David\'s persecution?) is unknown — the Psalm presents an archetypal experience of abandonment and vindication. The pattern: intense lament (vv. 1-21) → sudden transition to praise (v. 22) → eschatological proclamation (vv. 27-31: \'all the families of the nations shall worship before you ... posterity shall serve him; it shall be told of the Lord to the coming generation\'). The Psalm functions in NT usage not as a prediction of specific details but as the divinely-given interpretive framework for understanding the cross: suffering-unto-vindication, abandonment-unto-universal-proclamation.</p>"
  },
  "110": {
    "1": "<p>Psalm 110 is the most frequently quoted OT text in the NT. Jesus cites it in the Synoptics (Matt 22:41-46 and parallels) as a riddle about the Messiah\'s nature. Peter cites it at Pentecost (Acts 2:34-35). Paul cites it (1 Cor 15:25; Eph 1:20; Col 3:1). Hebrews cites or alludes to it eight times (1:3, 13; 5:6, 10; 6:20; 7:17, 21; 8:1; 10:12-13). Its dominance in NT Christology is due to its dual claim: (1) divine enthronement at God\'s right hand; (2) eternal Melchizedekian priesthood. These two — divine lordship and perfect priesthood — are the two Christological pillars the NT builds on from this one Psalm.</p>"
  }
}

PSA_CHRIST = {
  "2": {
    "7": "<p>A direct revelation: \'You are my Son; today I have begotten you.\' The royal Psalm 2 reaches its Christological fullness in the resurrection. Paul at Pisidian Antioch (Acts 13:33): God raised Jesus, \'as it is written in the second Psalm, You are my Son, today I have begotten you.\' The \'today\' of divine fatherhood is not the eternal generation alone but the specific day of the resurrection-enthronement, when the Son\'s identity is publicly declared. Every application of Ps 2:7 in the NT (baptism, transfiguration, resurrection) marks a moment when the Father publicly declares the Son\'s identity for the community to hear.</p>"
  },
  "22": {
    "1": "<p>A fulfillment: \'My God, my God, why have you forsaken me?\' The Passion Psalm that Jesus cited from the cross is both a historical lament (David in extremity) and a Christological prophecy (the Son\'s abandonment in the atonement). The cry \'why have you forsaken me\' is not a failure of faith but a genuine experience of divine absence — the moment when Christ bore the full weight of human sin-under-judgment. The Psalm\'s movement (dereliction → trust → vindication → universal proclamation) is the death-and-resurrection narrative in miniature. Jesus did not die in despair; the Psalm he cited ends in the world\'s worship of YHWH through the one who suffered.</p>"
  },
  "110": {
    "1": "<p>A direct revelation: \'The LORD says to my Lord: Sit at my right hand until I make your enemies your footstool.\' The most foundational Christological oracle in the OT: the risen and ascended Christ is enthroned at the Father\'s right hand (the supreme position of divine authority) awaiting the final subjection of all enemies, including death (1 Cor 15:25-26). The present era is the era of Christ\'s enthronement: he reigns now, his enemies are being progressively placed under his feet, and the ultimate subjection is certain. Ps 110:1 frames the entire NT\'s understanding of the ascension and the present Christological situation of the cosmos.</p>",
    "4": "<p>A fulfillment: \'You are a priest forever after the order of Melchizedek.\' The divine oath of the eternal priesthood is fulfilled in Christ\'s resurrection, which established him as the priest who never dies. Unlike the Levitical priests who needed to offer sacrifice repeatedly and who were replaced by death, Christ offered himself once and lives forever in the power of an indestructible life (Heb 7:16, 24-25). The Melchizedekian priesthood — prior to Aaron, not from the tribe of Levi, without recorded end — is the OT\'s own signal that the Levitical system was provisional. Christ\'s eternal intercession (\'he always lives to make intercession for them\', Heb 7:25) is the fulfillment of Ps 110:4\'s oath.</p>"
  }
}

def main():
    e = load_echo('psalms')
    merge_echo(e, PSA_ECHO)
    save_echo('psalms', e)
    print(f'Psalms echo: {len(e)} chapters, {sum(len(v) for v in e.values())} verses')

    c = load_comm('mkt-original', 'psalms')
    merge_comm(c, PSA_ORIGINAL)
    save_comm('mkt-original', 'psalms', c)
    print(f'Psalms original: {len(c)} chapters, {sum(len(v) for v in c.values())} verses')

    c = load_comm('mkt-context', 'psalms')
    merge_comm(c, PSA_CONTEXT)
    save_comm('mkt-context', 'psalms', c)
    print(f'Psalms context: {len(c)} chapters, {sum(len(v) for v in c.values())} verses')

    c = load_comm('mkt-christ', 'psalms')
    merge_comm(c, PSA_CHRIST)
    save_comm('mkt-christ', 'psalms', c)
    print(f'Psalms christ: {len(c)} chapters, {sum(len(v) for v in c.values())} verses')

if __name__ == '__main__':
    main()
